1	use crate::expr::UseKind;
2	use crate::span::Span;
3	use crate::token_type::TokenType::Pound;
4	use crate::type_env::{nil_type, Type};
5	use crate::{error, expr::Expr, token::Token, token_type::TokenType};
6	
7	pub struct Parser<'a> {
8	    tokens: &'a [Token],
9	    current: usize,
10	}
11	
12	impl<'a> Parser<'a> {
13	    pub fn new(tokens: &'a [Token]) -> Self {
14	        Self { tokens, current: 0 }
15	    }
16	
17	    // ---------- ENTRY ----------
18	    pub fn parse(&mut self) -> Expr {
19	        let mut statements = Vec::new();
20	
21	        while !self.is_at_end() {
22	            statements.push(Box::new(self.statement()));
23	            if !self.match_any(&[TokenType::Semicolon]) && !self.is_at_end() {
24	                let t = self.peek();
25	                error(
26	                    self.get_span(),
27	                    format!("Expected ';' after statement. Found '{}'", t.token_type).as_str(),
28	                    "parsing",
29	                );
30	                self.advance();
31	            }
32	        }
33	
34	        Expr::StmtBlock(statements, self.get_span())
35	    }
36	
37	    // ---------- STATEMENTS ----------
38	    fn statement(&mut self) -> Expr {
39	        if self.match_any(&[TokenType::Dollar]) {
40	            return self.print();
41	        }
42	
43	        if self.match_any(&[TokenType::Ret]) {
44	            return self.return_stmt();
45	        }
46	
47	        if self.match_any(&[Pound]) {
48	            return self.while_loop();
49	        }
50	
51	        if self.match_any(&[TokenType::Fn]) {
52	            return self.define_function();
53	        }
54	
55	        if self.match_any(&[TokenType::Hash]) {
56	            return self.declaration();
57	        }
58	
59	        if self.match_any(&[TokenType::Del]) {
60	            return self.delete();
61	        }
62	
63	        if self.match_any(&[TokenType::QuestionMark]) {
64	            return self.if_statement(false);
65	        }
66	
67	        if self.match_any(&[TokenType::Use]) {
68	            return self.use_file();
69	        }
70	
71	        if self.match_any(&[TokenType::For]) {
72	            return self.for_loop();
73	        }
74	
75	        if self.match_any(&[TokenType::Cls]) {
76	            return self.class();
77	        }
78	
79	        Expr::Stmt(Box::new(self.expression()))
80	    }
81	
82	    // ---------- USE ------------
83	
84	    fn use_file(&mut self) -> Expr {
85	        let kind = if self.match_any(&[TokenType::Std]) {
86	            UseKind::Std
87	        } else {
88	            UseKind::Normal
89	        };
90	        self.consume(TokenType::String, "Expected file name after 'use' keyword");
91	        Expr::Use {
92	            kind,
93	            path: self.previous().literal,
94	            span: self.get_span(),
95	        }
96	    }
97	
98	    // ---------- BLOCK ----------
99	    fn statement_block(&mut self) -> Expr {
100	        let mut statements = Vec::new();
101	
102	        while !self.check(TokenType::RightBrace) && !self.is_at_end() {
103	            let statement = self.statement();
104	
105	            if !self.check(TokenType::Semicolon) && !self.check(TokenType::RightBrace) {
106	                let t = self.peek();
107	                error(
108	                    self.get_span(),
109	                    format!("Expected ';' after statement. Found '{}'", t.token_type).as_str(),
110	                    "parsing",
111	                );
112	                self.advance();
113	            }
114	            if self.match_any(&[TokenType::Semicolon]) {
115	                statements.push(Box::new(Expr::Discard(Box::new(statement))));
116	            } else {
117	                statements.push(Box::new(statement));
118	            }
119	        }
120	
121	        self.consume(TokenType::RightBrace, "Expected '}' after block.");
122	        Expr::StmtBlockWithScope(statements, self.get_span())
123	    }
124	
125	    // ---------- DELETE VAR -----------
126	
127	    fn delete(&mut self) -> Expr {
128	        if self.match_any(&[TokenType::Ident]) {
129	            Expr::Delete(self.previous().lexeme)
130	        } else {
131	            error(
132	                self.get_span(),
133	                "Expected variable name after 'del'.",
134	                "parsing",
135	            );
136	            Expr::Nothing()
137	        }
138	    }
139	
140	    // ---------- NEW CLASS -----------
141	
142	    fn class(&mut self) -> Expr {
143	        self.consume(TokenType::Ident, "Expected class name after 'cls'.");
144	        let name = self.previous().lexeme;
145	        self.consume(TokenType::LeftBrace, "Expected '{' after class name");
146	
147	        let mut members = Vec::new();
148	
149	        while !self.match_any(&[TokenType::RightBrace]) {
150	            self.consume(
151	                TokenType::Ident,
152	                "Expected an identifier at start of line (in class declaration)",
153	            );
154	            let name = self.previous().lexeme;
155	            self.consume(
156	                TokenType::Colon,
157	                "Expected colon after identifier in class declaration",
158	            );
159	
160	            members.push((name, self.get_type()));
161	        }
162	
163	        let class_type = Type::simple(&name);
164	
165	        Expr::Class(class_type, members, self.get_span())
166	    }
167	    // ---------- MEMBER VARIABLE -----------
168	
169	    fn member(&mut self) -> Expr {
170	        let variable = self.nth();
171	
172	        if self.match_any(&[TokenType::Dot]) {
173	            let member = self.ident();
174	
175	            Expr::Member(Box::new(variable), member, self.get_span())
176	        } else {
177	            variable
178	        }
179	    }
180	
181	    // ---------- WHILE LOOP -----------
182	
183	    fn while_loop(&mut self) -> Expr {
184	        let cond = self.expression();
185	        // self.current += 1;
186	        let block = if self.match_any(&[TokenType::LeftBrace]) {
187	            self.statement_block()
188	        } else {
189	            error(
190	                self.get_span(),
191	                ("Expected '{' after 'while' condition, found '".to_string()
192	                    + self.previous().lexeme.as_str()
193	                    + "'")
194	                    .as_str(),
195	                "parsing",
196	            );
197	            Expr::Nothing()
198	        };
199	
200	        Expr::While(Box::new(cond), Box::new(block))
201	    }
202	
203	    // ----------- FOR LOOP -----------
204	
205	    fn for_loop(&mut self) -> Expr {
206	        self.consume(TokenType::Ident, "Expected identifier after 'For' token");
207	        let loopee = self.previous().lexeme;
208	        self.consume(TokenType::Colon, "Expected ':' after loopee");
209	        let looper = self.expression();
210	        self.consume(TokenType::LeftBrace, "Expected '{' after looper");
211	        let block = self.statement_block();
212	
213	        Expr::For(loopee, Box::new(looper), Box::new(block), self.get_span())
214	    }
215	
216	    // ---------- DECLARATION ----------
217	    fn declaration(&mut self) -> Expr {
218	        let is_mutable = self.match_any(&[TokenType::At]);
219	
220	        self.consume(TokenType::Ident, "Expected variable name.");
221	        let name = self.previous().lexeme.clone();
222	
223	        let var_type = if self.match_any(&[TokenType::Colon]) {
224	            Some(self.get_type())
225	        } else {
226	            None
227	        };
228	        let expr = if self.match_any(&[TokenType::Equal]) {
229	            Some(Box::new(self.expression()))
230	        } else {
231	            None
232	        };
233	
234	        if var_type.is_none() && expr.is_none() {
235	            let span = self.get_span();
236	            error(
237	                span,
238	                "Expected type or expression or both, got neither",
239	                "parsing",
240	            );
241	        }
242	        Expr::Declare(name, var_type, expr, is_mutable, self.get_span())
243	    }
244	
245	    // ------- ASSIGNMENT -----------
246	
247	    fn assignment(&mut self) -> Expr {
248	        let left = self.bools();
249	        if self.match_any(&[TokenType::Equal]) {
250	            let right = self.bools();
251	            Expr::Assign(Box::new(left), Box::new(right), self.get_span())
252	        } else {
253	            left
254	        }
255	    }
256	    // ------- IF / ELSE IF / ELSE ----
257	
258	    fn if_statement(&mut self, is_expr: bool) -> Expr {
259	        let if_cond = self.expression();
260	        // self.current += 1;
261	        let if_block = if self.match_any(&[TokenType::LeftBrace]) {
262	            self.statement_block()
263	        } else {
264	            error(
265	                self.get_span(),
266	                ("Expected '{' after 'if' condition, found '".to_string()
267	                    + self.previous().lexeme.as_str()
268	                    + "'")
269	                    .as_str(),
270	                "parsing",
271	            );
272	            Expr::Nothing()
273	        };
274	
275	        let mut else_block = None;
276	
277	        if self.match_any(&[TokenType::TildeQuestionMark]) {
278	            else_block = Some(Box::new(self.if_statement(is_expr)));
279	        } else if self.match_any(&[TokenType::Tilde]) {
280	            self.consume(TokenType::LeftBrace, "Expected '{' after 'TILDE'.");
281	            else_block = Some(Box::new(self.statement_block()));
282	        }
283	
284	        Expr::If(Box::new(if_cond), Box::new(if_block), else_block, is_expr)
285	    }
286	    // ---------- PRINT ---------------
287	    fn print(&mut self) -> Expr {
288	        if self.peek().token_type == TokenType::Dollar {
289	            self.advance();
290	            Expr::StmtBlock(
291	                vec![
292	                    Box::new(self.print()),
293	                    Box::new(Expr::Print(
294	                        Box::new(Expr::Str("\n".to_string())),
295	                        self.get_span(),
296	                    )),
297	                ],
298	                self.get_span(),
299	            )
300	        } else if self.peek().token_type == TokenType::Semicolon {
301	            Expr::Nothing()
302	        } else {
303	            Expr::Print(Box::new(self.expression()), self.get_span())
304	        }
305	    }
306	
307	    // ---------- FUNCTIONS ------------
308	
309	    fn define_function(&mut self) -> Expr {
310	        let mut generic_params = vec![];
311	
312	        if self.match_any(&[TokenType::LessLess]) {
313	            loop {
314	                self.consume(TokenType::Ident, "Expected generic name");
315	                generic_params.push(self.previous().lexeme);
316	
317	                if !self.match_any(&[TokenType::Comma]) {
318	                    break;
319	                }
320	            }
321	            self.consume(TokenType::GreaterGreater, "Expected '>'");
322	        }
323	
324	        let name = self.advance().lexeme;
325	
326	        let start_span = self.get_span();
327	
328	        let parameters: Vec<(String, Type)> = if self.match_any(&[TokenType::LeftParen]) {
329	            let mut parameters = vec![];
330	            while !self.is_at_end() && !self.check(TokenType::RightParen) {
331	                let name = self.advance().lexeme;
332	                self.consume(TokenType::Colon, "Expected ':' after parameter name.");
333	                let var_type = self.get_type();
334	                parameters.push((name, var_type));
335	                if !self.match_any(&[TokenType::Comma]) {
336	                    break;
337	                }
338	            }
339	
340	            self.consume(
341	                TokenType::RightParen,
342	                "Expected ')' after function parameters.",
343	            );
344	            parameters
345	        } else {
346	            vec![]
347	        };
348	
349	        let return_type = if !self.check(TokenType::LeftBrace) {
350	            Some(self.get_type())
351	        } else {
352	            None
353	        };
354	
355	        self.consume(
356	            TokenType::LeftBrace,
357	            "Expected '{' after function declaration.",
358	        );
359	
360	        let body = Box::new(self.statement_block());
361	
362	        Expr::DeclareFunction(
363	            name,
364	            body,
365	            return_type,
366	            parameters,
367	            generic_params,
368	            start_span,
369	        )
370	    }
371	
372	    fn define_lambda(&mut self) -> Expr {
373	        let mut generic_params = vec![];
374	
375	        if self.match_any(&[TokenType::LessLess]) {
376	            loop {
377	                self.consume(TokenType::Ident, "Expected generic name");
378	                generic_params.push(self.previous().lexeme);
379	
380	                if !self.match_any(&[TokenType::Comma]) {
381	                    break;
382	                }
383	            }
384	            self.consume(TokenType::GreaterGreater, "Expected '>'");
385	        }
386	
387	        let parameters: Vec<(String, Type)> = if self.match_any(&[TokenType::LeftParen]) {
388	            let mut parameters = vec![];
389	            while !self.is_at_end() && !self.check(TokenType::RightParen) {
390	                let name = self.advance().lexeme;
391	                self.consume(TokenType::Colon, "Expected ':' after parameter name.");
392	                let var_type = self.get_type();
393	                parameters.push((name, var_type));
394	                if !self.match_any(&[TokenType::Comma]) {
395	                    break;
396	                }
397	            }
398	
399	            self.consume(
400	                TokenType::RightParen,
401	                "Expected ')' after function parameters.",
402	            );
403	            parameters
404	        } else {
405	            vec![]
406	        };
407	
408	        let return_type = if !self.check(TokenType::LeftBrace) {
409	            self.get_type()
410	        } else {
411	            nil_type()
412	        };
413	
414	        self.consume(
415	            TokenType::LeftBrace,
416	            "Expected '{' after function declaration.",
417	        );
418	
419	        let body = Box::new(self.statement_block());
420	
421	        Expr::Function(body, return_type, parameters, generic_params)
422	    }
423	
424	    fn return_stmt(&mut self) -> Expr {
425	        let value = self.expression();
426	        Expr::Return(Box::new(value), self.get_span())
427	    }
428	
429	    fn call_function(&mut self, name: String) -> Expr {
430	        let mut generics = vec![];
431	
432	        if self.match_any(&[TokenType::LessLess]) {
433	            loop {
434	                generics.push(self.get_type());
435	
436	                if !self.match_any(&[TokenType::Comma]) {
437	                    break;
438	                }
439	            }
440	            self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
441	        }
442	
443	        self.consume(TokenType::LeftParen, "Expected '(' after function name.");
444	
445	        let mut arguments = vec![];
446	
447	        if !self.check(TokenType::RightParen) {
448	            loop {
449	                arguments.push(Box::new(self.expression()));
450	                if !self.match_any(&[TokenType::Comma]) {
451	                    break;
452	                }
453	            }
454	        }
455	
456	        self.consume(TokenType::RightParen, "Missing ')' after function call.");
457	
458	        Expr::CallFunc(name, generics, arguments, self.get_span())
459	    }
460	
461	    // ---------- EXPRESSIONS ----------
462	    fn expression(&mut self) -> Expr {
463	        self.assignment()
464	    }
465	
466	    fn bools(&mut self) -> Expr {
467	        let mut expr = self.compare();
468	
469	        while self.match_any(&[TokenType::And, TokenType::Or]) {
470	            let op = self.previous().token_type;
471	            let right = self.compare();
472	            expr = match op {
473	                TokenType::And => Expr::And(Box::new(expr), Box::new(right), self.get_span()),
474	                TokenType::Or => Expr::Or(Box::new(expr), Box::new(right), self.get_span()),
475	                _ => unreachable!(),
476	            };
477	        }
478	
479	        expr
480	    }
481	
482	    fn compare(&mut self) -> Expr {
483	        let mut expr = self.term();
484	
485	        while self.match_any(&[
486	            TokenType::EqualEqual,
487	            TokenType::BangEqual,
488	            TokenType::Greater,
489	            TokenType::GreaterEqual,
490	            TokenType::Less,
491	            TokenType::LessEqual,
492	        ]) {
493	            let op = self.previous().token_type;
494	            let right = self.term();
495	            expr = match op {
496	                TokenType::EqualEqual => {
497	                    Expr::EqualEqual(Box::new(expr), Box::new(right), self.get_span())
498	                }
499	                TokenType::BangEqual => {
500	                    Expr::BangEqual(Box::new(expr), Box::new(right), self.get_span())
501	                }
502	                TokenType::Greater => {
503	                    Expr::Greater(Box::new(expr), Box::new(right), self.get_span())
504	                }
505	                TokenType::GreaterEqual => {
506	                    Expr::GreaterEqual(Box::new(expr), Box::new(right), self.get_span())
507	                }
508	                TokenType::Less => Expr::Less(Box::new(expr), Box::new(right), self.get_span()),
509	                TokenType::LessEqual => {
510	                    Expr::LessEqual(Box::new(expr), Box::new(right), self.get_span())
511	                }
512	                _ => unreachable!(),
513	            };
514	        }
515	
516	        expr
517	    }
518	
519	    fn term(&mut self) -> Expr {
520	        let mut expr = self.factor();
521	
522	        while self.match_any(&[TokenType::Plus, TokenType::Minus]) {
523	            let op = self.previous().token_type;
524	            let right = self.factor();
525	            expr = match op {
526	                TokenType::Plus => Expr::Add(Box::new(expr), Box::new(right), self.get_span()),
527	                TokenType::Minus => Expr::Sub(Box::new(expr), Box::new(right), self.get_span()),
528	                _ => unreachable!(),
529	            };
530	        }
531	
532	        expr
533	    }
534	
535	    fn factor(&mut self) -> Expr {
536	        let mut expr = self.unary();
537	
538	        while self.match_any(&[TokenType::Star, TokenType::Slash, TokenType::Mod]) {
539	            let op = self.previous().token_type;
540	            let right = self.unary();
541	            expr = match op {
542	                TokenType::Star => Expr::Mult(Box::new(expr), Box::new(right), self.get_span()),
543	                TokenType::Slash => Expr::Div(Box::new(expr), Box::new(right), self.get_span()),
544	                TokenType::Mod => Expr::Mod(Box::new(expr), Box::new(right), self.get_span()),
545	                _ => unreachable!(),
546	            };
547	        }
548	
549	        expr
550	    }
551	
552	    fn unary(&mut self) -> Expr {
553	        if self.match_any(&[TokenType::Minus]) {
554	            return Expr::Sub(
555	                Box::new(Expr::Nothing()),
556	                Box::new(self.unary()),
557	                self.get_span(),
558	            );
559	        }
560	
561	        if self.match_any(&[TokenType::Plus]) {
562	            return Expr::Add(
563	                Box::new(Expr::Nothing()),
564	                Box::new(self.unary()),
565	                self.get_span(),
566	            );
567	        }
568	
569	        if self.match_any(&[TokenType::Bang]) {
570	            return Expr::Not(Box::new(self.unary()), self.get_span());
571	        }
572	
573	        if self.match_any(&[TokenType::And]) {
574	            // ref: create a reference to a variable
575	            return if self.check(TokenType::Ident) {
576	                self.advance(); // consume the identifier
577	                let inner = Box::new(Expr::Variable(
578	                    self.previous().lexeme.clone(),
579	                    self.get_span(),
580	                ));
581	                Expr::Ref(inner, self.get_span())
582	            } else {
583	                error(self.get_span(), "Expected identifier after '&'.", "parsing");
584	                Expr::Nothing()
585	            };
586	        }
587	
588	        if self.match_any(&[TokenType::Star]) {
589	            let inner = Box::new(self.unary());
590	            return Expr::Deref(inner, self.get_span());
591	        }
592	
593	        self.power()
594	    }
595	
596	    fn power(&mut self) -> Expr {
597	        let mut expr = self.member();
598	
599	        while self.match_any(&[TokenType::StarStar]) {
600	            expr = Expr::Power(Box::new(expr), Box::new(self.member()), self.get_span());
601	        }
602	
603	        expr
604	    }
605	    fn nth(&mut self) -> Expr {
606	        let val = self.primary();
607	        if self.match_any(&[TokenType::LeftBrack]) {
608	            let expr = self.expression();
609	            self.consume(TokenType::RightBrack, "Expected ']' after indexing.");
610	            Expr::Nth(Box::new(val), Box::new(expr), self.get_span())
611	        } else {
612	            val
613	        }
614	    }
615	
616	    fn vector_lit(&mut self) -> Expr {
617	        if self.match_any(&[TokenType::LeftBrace]) {
618	            let mut exprs = vec![];
619	
620	            let mut last_expr = false;
621	            while !self.match_any(&[TokenType::RightBrace]) && !last_expr {
622	                let expr = self.expression();
623	                exprs.push(expr);
624	                if !self.match_any(&[TokenType::Comma]) {
625	                    last_expr = true;
626	                }
627	            }
628	
629	            Expr::Vector(exprs)
630	        } else {
631	            self.consume(TokenType::LeftBrace, "Expected '{' after '\\''.");
632	            Expr::Nothing()
633	        }
634	    }
635	
636	    fn array_lit(&mut self) -> Expr {
637	        let mut exprs = vec![];
638	
639	        let mut last_expr = false;
640	        while !self.match_any(&[TokenType::RightBrack]) && !last_expr {
641	            let expr = self.expression();
642	            exprs.push(expr);
643	            if !self.match_any(&[TokenType::Comma]) {
644	                last_expr = true;
645	            }
646	        }
647	
648	        Expr::Array(exprs)
649	    }
650	
651	    // ---------- PRIMARY ----------
652	    fn primary(&mut self) -> Expr {
653	        if self.match_any(&[TokenType::LeftBrace]) {
654	            return self.statement_block();
655	        }
656	
657	        if self.check(TokenType::Ident) {
658	            let item = self.item();
659	
660	            if self.check(TokenType::LeftParen) || self.check(TokenType::LessLess) {
661	                return self.call_function(item);
662	            }
663	            return Expr::Variable(item, self.get_span());
664	        }
665	
666	        if self.match_any(&[TokenType::Float]) {
667	            return Expr::Float(self.previous().literal.parse().unwrap_or(0.0));
668	        }
669	
670	        if self.match_any(&[TokenType::Int]) {
671	            return Expr::Int(self.previous().literal.parse().unwrap_or(0));
672	        }
673	
674	        if self.match_any(&[TokenType::True]) {
675	            return Expr::Bool(true);
676	        }
677	
678	        if self.match_any(&[TokenType::False]) {
679	            return Expr::Bool(false);
680	        }
681	
682	        if self.match_any(&[TokenType::String]) {
683	            return Expr::Str(self.previous().literal.clone());
684	        }
685	
686	        if self.match_any(&[TokenType::Char]) {
687	            return Expr::Char(self.previous().literal.clone());
688	        }
689	
690	        if self.match_any(&[TokenType::LeftParen]) {
691	            let expr = self.expression();
692	            self.consume(TokenType::RightParen, "Expected ')'.");
693	            return expr;
694	        }
695	
696	        if self.match_any(&[TokenType::QuestionMark]) {
697	            return self.if_statement(true);
698	        }
699	
700	        if self.match_any(&[TokenType::This]) {
701	            return Expr::This(self.get_span());
702	        }
703	
704	        if self.match_any(&[TokenType::Lam]) {
705	            return self.define_lambda();
706	        }
707	
708	        if self.match_any(&[TokenType::BackSlash]) {
709	            return self.vector_lit();
710	        }
711	
712	        if self.match_any(&[TokenType::LeftBrack]) {
713	            return self.array_lit();
714	        }
715	
716	        Expr::Nothing()
717	    }
718	
719	    fn get_type(&mut self) -> Type {
720	        if self.match_any(&[TokenType::Ident]) {
721	            let name = self.previous().lexeme.clone();
722	
723	            if self.match_any(&[TokenType::LessLess]) {
724	                let mut gens = vec![];
725	
726	                loop {
727	                    gens.push(self.get_type());
728	                    if !self.match_any(&[TokenType::Comma]) {
729	                        break;
730	                    }
731	                }
732	
733	                self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
734	                return Type::with_generics(&name, gens);
735	            }
736	
737	            return Type::simple(&name);
738	        } else if self.match_any(&[TokenType::LeftBrack]) {
739	            let mut gens = vec![];
740	
741	            loop {
742	                gens.push(self.get_type());
743	                if !self.match_any(&[TokenType::Comma]) {
744	                    break;
745	                }
746	            }
747	
748	            self.consume(TokenType::RightBrack, "Expected '>' after generics");
749	            return Type::with_generics("arr", gens);
750	        } else if self.match_any(&[TokenType::And]) {
751	            return Type::with_generics("ref", vec![self.get_type()]);
752	        }
753	
754	        error(self.get_span(), "Expected type", "parsing");
755	
756	        nil_type()
757	    }
758	
759	    // ---------- UTIL ----------
760	    fn get_span(&self) -> Span {
761	        let token = self.previous();
762	        Span {
763	            line: token.line,
764	            column: token.column,
765	        }
766	    }
767	
768	    fn item(&mut self) -> String {
769	        self.consume(TokenType::Ident, "Expected item.");
770	        let item = self.previous().lexeme.clone();
771	        item
772	    }
773	
774	    fn ident(&mut self) -> String {
775	        self.consume(TokenType::Ident, "Expected identifier.");
776	        let ident = self.previous().lexeme.clone();
777	        ident
778	    }
779	
780	    fn match_any(&mut self, types: &[TokenType]) -> bool {
781	        for t in types {
782	            if self.check(*t) {
783	                self.advance();
784	                return true;
785	            }
786	        }
787	        false
788	    }
789	    fn check(&self, token_type: TokenType) -> bool {
790	        !self.is_at_end() && self.peek().token_type == token_type
791	    }
792	
793	    fn peek_next(&self, token_type: TokenType) -> bool {
794	        self.tokens
795	            .get(self.current + 1)
796	            .map(|t| t.token_type == token_type)
797	            .unwrap_or(false)
798	    }
799	
800	    fn peek_next_next(&self, token_type: TokenType) -> bool {
801	        self.tokens
802	            .get(self.current + 2)
803	            .map(|t| t.token_type == token_type)
804	            .unwrap_or(false)
805	    }
806	
807	    fn consume(&mut self, token_type: TokenType, message: &str) -> Token {
808	        if self.check(token_type) {
809	            self.advance()
810	        } else {
811	            let t = self.peek();
812	            error(
813	                self.get_span(),
814	                format!("{} Found: {}", message, t.token_type).as_str(),
815	                "parsing",
816	            );
817	            self.advance();
818	            Token::nil()
819	        }
820	    }
821	
822	    fn advance(&mut self) -> Token {
823	        if !self.is_at_end() {
824	            self.current += 1;
825	        }
826	        self.previous()
827	    }
828	
829	    fn is_at_end(&self) -> bool {
830	        self.peek().token_type == TokenType::EOF
831	    }
832	
833	    fn peek(&self) -> Token {
834	        self.tokens
835	            .get(self.current)
836	            .cloned()
837	            .unwrap_or_else(Token::nil)
838	    }
839	
840	    fn previous(&self) -> Token {
841	        self.tokens
842	            .get(self.current.saturating_sub(1))
843	            .cloned()
844	            .unwrap_or_else(Token::nil)
845	    }
846	}
847	
848	// Grammar:
849	/*
850	statement_block -> "{" ( statement )* "}"
851	statement       -> ( print | declaration | expression | return | function ) ";"
852	
853	print           -> "$" ( "$" )? expression
854	declaration     -> "#" ( "@" )? IDENTIFIER ( ":" type )? ( "=" expression )? // need one or both
855	return          -> "ret" expression
856	while           -> "£" expression statement_block
857	
858	if_statement    -> "?" expression statement_block ( "~?" expression statement_block )* ( "~" statement_block )?
859	function_call   -> IDENTIFIER "(" (expression)* ")"
860	function        -> "fn" ( "<<" IDENTIFIER* ">>" )? IDENTIFIER ( "(" (IDENTIFIER ":" IDENTIFIER)* ")" )? type? statement_block
861	
862	type            -> IDENTIFIER | "[" type* "]" | "<<" type* ">>"
863	
864	expression      -> bool
865	bool            -> compare ( ( "&" | "|" ) compare )*
866	compare         -> term ( ( "==" | ">=" | "<=" | ">" | "<" | "!=" ) term )*
867	term            -> factor ( ( "+" | "-" ) factor )*
868	factor          -> unary ( ( "*" | "/" | "%" ) unary )*
869	unary           -> ( "-" | "+" ) unary | power
870	power           -> nth ( ( "**" ) nth )*
871	nth             -> primary ( "[" expression "]" )?
872	primary         -> NUMBER | STRING | BOOLEAN | IDENTIFIER | "(" expression ")" | statement_block | if_statement | function_call
873	
874	*/
