585	    pub fn pre_transpile(
586	        &self,
587	        cte: &mut CompileTimeEnv,
588	        ctx: &mut CodeGenContext,
589	        programs_to_transpile: &mut HashMap<String, bool>,
590	        current_file_dir: &str,
591	    ) {
592	        match self {
593	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
594	                if cte.get_var(name).is_some() {
595	                    error(
596	                    *span,
597	                    format!(
598	                        "Variable '{}' already exists and is immutable, could not declare function",
599	                        name
600	                    )
601	                        .as_str(),"pre-transpiling"
602	                );
603	                }
604	                let mut arg_types = vec![];
605	                for arg in args {
606	                    arg_types.push(arg.1.clone());
607	                }
608	
609	                // Push scope and declare parameters.
610	                cte.push_scope();
611	                for arg in args {
612	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
613	                }
614	
615	                // Process the body first so local variable declarations (like #x = ...)
616	                // are registered in the scope. This makes them visible to returned_type()
617	                // and get_type() calls that resolve variable names.
618	                block.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
619	
620	                let ret_type = block.returned_type(cte, *span);
621	                let return_type = if return_type.is_some() {
622	                    return_type.clone().unwrap()
623	                } else {
624	                    if let Some(ty) = ret_type.clone() {
625	                        ty
626	                    } else {
627	                        nil_type()
628	                    }
629	                };
630	
631	                cte.add_func_type(return_type.clone(), arg_types.clone(), ctx, *span);
632	                // Declare the variable first so c_func_instance_name can find it
633	                cte.declare_global_var(
634	                    name.clone(),
635	                    false,
636	                    Type::with_generics("func", {
637	                        arg_types.push(return_type.clone());
638	                        let output = arg_types;
639	                        output
640	                    }),
641	                );
642	
643	                let return_type_name = cte.c_type_name(&return_type, ctx, *span);
644	                let func_name = cte.c_func_instance_name(&name, &[], *span);
645	
646	                let mut decl_params: Vec<String> = Vec::new();
647	                for arg in args {
648	                    let param = cte.c_param_type(&arg.1, ctx, *span);
649	                    let var = cte.c_var_name(&arg.0, *span);
650	                    decl_params.push(format!("{} {}", param, var));
651	                }
652	                ctx.declarations
653	                    .push_str(&format!("{} {}(", return_type_name, func_name));
654	                ctx.declarations.push_str(&decl_params.join(", "));
655	                ctx.declarations.push_str(");\n");
656	
657	                cte.pop_scope();
658	            }
659	            Expr::Use { kind, path, span } => {
660	                let full_path = match kind {
661	                    UseKind::Std => format!("{}{}", STD_PATH, path),
662	                    UseKind::Normal => {
663	                        if current_file_dir.is_empty() {
664	                            path.to_string()
665	                        } else {
666	                            format!("{}/{}", current_file_dir, path)
667	                        }
668	                    }
669	                };
670	
671	                if !Path::new(&full_path).exists() {
672	                    error(*span, "File does not exist!", "pre-transpiling");
673	                    return;
674	                }
675	
676	                if !programs_to_transpile.contains_key(&full_path) {
677	                    programs_to_transpile.insert(full_path.clone(), true);
678	                    // Process this file immediately so its functions are available to subsequent
679	                    // declarations in the current file
680	                    let source = std::fs::read_to_string(&full_path)
681	                        .unwrap_or_else(|_| panic!("Failed to read {}", full_path));
682	                    let imported_ast = {
683	                        let mut scanner = crate::scanner::Scanner::new(source.clone());
684	                        let tokens = scanner.scan_tokens();
685	                        let mut parser = crate::parser::Parser::new(tokens);
686	                        parser.parse()
687	                    };
688	                    let imported_dir = std::path::Path::new(&full_path)
689	                        .parent()
690	                        .map(|p| p.to_string_lossy().to_string())
691	                        .unwrap_or_default();
692	                    imported_ast.pre_transpile(cte, ctx, programs_to_transpile, &imported_dir);
693	                }
694	            }
695	
696	            Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
697	                for expr in exprs {
698	                    expr.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
699	                }
700	            }
701	
702	            Expr::Discard(expr) => {
703	                expr.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir)
704	            }
705	
706	            Expr::Class(ty, members, span) => {
707	                cte.register_class(ty.clone());
708	
709	                for member in members {
710	                    cte.declare_member(member.0.clone(), member.1.clone(), ty.clone());
711	                }
712	
713	                let c_type_name = cte.c_type_name(ty, ctx, *span);
714	                ctx.include.push_str("struct ");
715	                ctx.include.push_str(&c_type_name);
716	                ctx.include.push_str(";\n");
717	
718	                ctx.types.push_str("\ntypedef struct ");
719	                ctx.types.push_str(&c_type_name);
720	                ctx.types.push(' ');
721	                ctx.types.push_str(&c_type_name);
722	                ctx.types.push_str(";\n");
723	            }
724	
725	            Expr::Declare(name, var_type, expr, is_mutable, _span) => {
726	                if let Some(var_type) = var_type {
727	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone());
728	                } else if let Some(expr_box) = expr {
729	                    let t = expr_box.get_type(cte);
730	                    cte.declare_var(name.clone(), *is_mutable, t);
731	                }
732	                if let Some(expr_box) = expr {
733	                    expr_box.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
734	                }
735	            }
736	
737	            _ => {}
738	        }
739	    }
