331	pub fn error(span: Span, message: &str, place: &str) {
332	    if !RUNNING_TESTS.lock().unwrap().clone() {
333	        report(span.line, span.column, message, place);
334	
335	        panic::set_hook(Box::new(|_| {}));
336	    }
337	}
338	
339	fn get_line(line: usize) -> String {
340	    let src = SOURCES.lock().unwrap();
341	    if !src.is_empty() {
342	        let source = src.last().unwrap();
343	        source
344	            .lines()
345	            .nth(line.saturating_sub(1))
346	            .unwrap_or("")
347	            .to_string()
348	    } else {
349	        String::new()
350	    }
351	}
352	
353	pub fn report(line: usize, column: usize, message: &str, place: &str) {
354	    let mut err = ERROR.lock().unwrap();
355	
356	    println!(
357	        "\n{BOLD}{ERROR_COLOR}error{RESET} {HELP_COLOR}({place}){RESET}{BOLD}: {message}{RESET}"
358	    );
359	
360	    println!("--> line {} column {}\n", line, column);
361	
362	    let source_line = get_line(line);
363	
364	    println!("    |");
365	    if line as isize - 3 > 0 {
366	        let prev_line = get_line(line - 3);
367	        println!("{CYAN}{:>3}{RESET} | {}", line - 3, prev_line);
368	    }
369	
370	    if line as isize - 2 > 0 {
371	        let prev_line = get_line(line - 2);
372	        println!("{CYAN}{:>3}{RESET} | {}", line - 2, prev_line);
373	    }
374	
375	    if line as isize - 1 > 0 {
376	        let prev_line = get_line(line - 1);
377	        println!("{CYAN}{:>3}{RESET} | {}", line - 1, prev_line);
378	    }
379	    println!("{CYAN}{:>3}{RESET} | {}", line, source_line);
380	
381	    let prefix_len = format!("{:>3}  | ", line).len();
382	    let caret_padding = " ".repeat((prefix_len + column).saturating_sub(3));
383	
384	    let mut caret_line = format!("{}{ERROR_COLOR}^{RESET} {message}", caret_padding);
385	
386	    caret_line.replace_range(4..4, "|");
387	
388	    println!("{}", caret_line);
389	
390	    let stack = CALL_STACK.lock().unwrap();
391	    if !stack.is_empty() {
392	        println!("\n{BOLD}Stack trace:{RESET}");
393	        for func in stack.iter().rev() {
394	            println!("  {BRIGHT_YELLOW}->{BRIGHT_BLUE} {}", func);
395	        }
396	    }
397	
398	    println!("{RESET}\n");
399	
400	    *err = Err(ObstructError::new(line, column, message));
401	}
402	
403	pub fn parse(source: String) -> Expr {
404	    let mut scanner = Scanner::new(source);
405	    let tokens = scanner.scan_tokens();
406	    let mut parser = Parser::new(tokens);
407	    let expr = parser.parse();
408	
409	    expr
410	}
411	
412	pub fn push_stack(name: &str) {
413	    CALL_STACK.lock().unwrap().push(name.to_string());
414	}
415	
416	pub fn pop_stack() {
417	    CALL_STACK.lock().unwrap().pop();
418	}
